// ประกอบ prompt จาก 3 แหล่ง: fill_instruction + alert context + RAG chunks
const job = $('Ingest Alert').first().json.case;
const sec = $('Split Out Sections').item.json;
const rag = $json;

const chunks = (rag.chunks ?? []).map((c, i) => `[${i + 1}] (${c.source_doc})\n${c.text}`).join('\n---\n');
const missing = rag.missing_techniques ?? [];

const a = job.alert;
const alertContext = [
  `Threat: ${job.threat_name}`,
  `Techniques: ${job.mitre_techniques.join(', ')}`,
  `Host: ${a.host}`,
  `Target user: ${a.target_user}`,
  `Source IP: ${a.source_ip}`,
  (a.event_id ? `Windows Event ID: ${a.event_id} (logon type ${a.logon_type})` : `Log source: ${a.log_source ?? '-'}`),
  `Wazuh rule: ${a.rule_id} — ${a.rule_description}`
].join('\n');

const missingBlock = missing.length
  ? `\n⚠️ ไม่มีข้อมูลใน knowledge base รองรับ technique: ${missing.join(', ')}\nให้แปะธง ⚠️ ในแถวที่เกี่ยวข้อง และห้ามแต่งขั้นตอนขึ้นเอง`
  : '';

const prompt = `คุณเป็น SOC analyst ที่เขียน Incident Response Playbook

${sec.fill_instruction}

--- ALERT CONTEXT ---
${alertContext}

--- KNOWLEDGE BASE (ใช้เฉพาะข้อมูลด้านล่างนี้เท่านั้น ห้ามเพิ่มจากความรู้ตัวเอง) ---
${chunks || '(ไม่พบข้อมูลรองรับ)'}
${missingBlock}

เขียนที่ระดับแนวทาง/วิธีการ (procedure) ไม่ต้องลงลึกคำสั่งเฉพาะ OS หรือ Event ID เจาะจง ถ้าหลาย OS มีแนวคิดเดียวกันให้ยุบรวมเป็นขั้นตอนเดียว (เช่น บล็อก source IP ที่ firewall แทนการแยก netsh/iptables) จะยกคำสั่งเป็นตัวอย่างสั้นๆ ได้ แต่ห้ามให้คำสั่งเป็นแกนหลักของขั้นตอน\n\nตอบเป็นตาราง Markdown เท่านั้น ไม่ต้องมีคำนำหรือคำสรุป`;

return { json: { phase: sec.phase, heading: sec.heading, prompt } };

const text = $json.candidates?.[0]?.content?.parts?.[0]?.text ?? '';
const meta = $('Build Prompt').item.json;

return {
  json: {
    phase: meta.phase,
    heading: meta.heading,
    content: text.trim()
  }
};

// ยุบ 3 items กลับเป็น 1 ก้อน
const job = $('Ingest Alert').first().json.case;
const ncsc = $('Assess Severity').first().json;
const cti = $('CTI Enrichment').first().json;
const sections = $input.all().map(i => i.json);

// รวม missing_techniques จากทุก phase
const allRag = $('Retrieve Chunks').all().map(i => i.json);
const missing = [...new Set(allRag.flatMap(r => r.missing_techniques ?? []))];
const fallbackUsed = allRag.some(r => r.fallback_used === true);

return [{
  json: {
    case_id: job.case_id,
    threat_name: job.threat_name,
    technique_ids: job.mitre_techniques,
    severity: job.severity,
    alert: job.alert,
    sections,
    missing_techniques: missing,
    fallback_used: fallbackUsed,
    cti: {
      ip: cti.ip,
      cti_verdict: cti.cti_verdict,
      reason: cti.reason,
      virustotal: cti.virustotal,
      abuseipdb: cti.abuseipdb
    },
    ncsc: {
      ncsc_category: ncsc.ncsc_category,
      category_name: ncsc.category_name,
      rationale: ncsc.rationale,
      escalation_owner: ncsc.escalation_owner,
      escalation_tier: ncsc.escalation_tier,
      sla_minutes: ncsc.sla_minutes
    }
  }
}];
